}

__kernel void normalize_weights_kernel(__global double * weights, int Nparticles, __global double* partial_sums, __global double * CDF, __global double * u, __global int * seed) {
    int i = get_global_id(0);
    __local double u1_local;
    __local double sumWeights_local;

    if (get_local_id(0) == 0)
        sumWeights_local = partial_sums[0];
    barrier(CLK_LOCAL_MEM_FENCE);

    if (i < Nparticles) {
        weights[i] = weights[i] / sumWeights_local;
    }

    barrier(CLK_GLOBAL_MEM_FENCE);

    if (i == 0) {
        CDF[0] = weights[0];
        for (int x = 1; x < Nparticles; x++) {
            CDF[x] = weights[x] + CDF[x - 1];
        }
        // d_randu equivalent
        int M = 2147483647;
        int A = 1103515245;
        int C = 12345;
        int num = A * seed[i] + C;
        seed[i] = num % M;
        u[0] = (1.0 / ((double) (Nparticles))) * fabs(seed[i] / ((double) M));
    }
    barrier(CLK_GLOBAL_MEM_FENCE);

    if (get_local_id(0) == 0)
        u1_local = u[0];
    barrier(CLK_LOCAL_MEM_FENCE);

    if (i < Nparticles) {
        u[i] = u1_local + ((double)i) / ((double)(Nparticles));
    }
}

__kernel void sum_kernel(__global double* partial_sums, int Nparticles) {
    int i = get_global_id(0);
    if (i == 0) {
        int num_blocks = (Nparticles + get_local_size(0) - 1) / get_local_size(0);
        double sum = 0.0;
        for (int x = 0; x < num_blocks; x++) {
            sum += partial_sums[x];
        }
        partial_sums[0] = sum;
    }
}

inline double dev_round_double(double value) {
    int newValue = (int)(value);
    if (value - newValue < .5)
        return (double)newValue;
    else
        return (double)(newValue + 1);
}

inline double d_randu(__global int * seed, int index) {
    int M = 2147483647;
    int A = 1103515245;
    int C = 12345;
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double) M));
}

inline double d_randn(__global int * seed, int index) {
    double pi = 3.14159265358979323846;
    double u = d_randu(seed, index);
    double v = d_randu(seed, index);
    double cosine = cos(2 * pi * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

inline double calcLikelihoodSum(__global unsigned char * I, __global int * ind, int numOnes, int index) {
    double likelihoodSum = 0.0;
    for (int x = 0; x < numOnes; x++) {
        double diff1 = (double)(I[ind[index * numOnes + x]] - 100);
        double diff2 = (double)(I[ind[index * numOnes + x]] - 228);
        likelihoodSum += (diff1 * diff1 - diff2 * diff2) / 50.0;
    }
    return likelihoodSum;
}

__kernel void likelihood_kernel(__global double * arrayX, __global double * arrayY, __global double * xj, __global double * yj, __global double * CDF, __global int * ind, __global int * objxy, __global double * likelihood, __global unsigned char * I, __global double * u, __global double * weights, int Nparticles, int countOnes, int max_size, int k, int IszY, int Nfr, __global int *seed, __global double* partial_sums) {
    int i = get_global_id(0);
    __local double buffer[512]; // assuming max 512 threads per block

    if (i < Nparticles) {
        arrayX[i] = xj[i];
        arrayY[i] = yj[i];
        weights[i] = 1.0 / ((double)(Nparticles));
        arrayX[i] = arrayX[i] + 1.0 + 5.0 * d_randn(seed, i);
        arrayY[i] = arrayY[i] - 2.0 + 2.0 * d_randn(seed, i);
    }
    barrier(CLK_GLOBAL_MEM_FENCE);

    if (i < Nparticles) {
        for (int y = 0; y < countOnes; y++) {
            int indX = (int)dev_round_double(arrayX[i]) + objxy[y * 2 + 1];
            int indY = (int)dev_round_double(arrayY[i]) + objxy[y * 2];
            int idx = abs(indX * IszY * Nfr + indY * Nfr + k);
            if (idx >= max_size)
                idx = 0;
            ind[i * countOnes + y] = idx;
        }
        likelihood[i] = calcLikelihoodSum(I, ind, countOnes, i);
        likelihood[i] = likelihood[i] / countOnes;
        weights[i] = weights[i] * exp(likelihood[i]);
    }
    barrier(CLK_GLOBAL_MEM_FENCE);

    buffer[get_local_id(0)] = 0.0;
    barrier(CLK_LOCAL_MEM_FENCE);

    if (i < Nparticles) {
        buffer[get_local_id(0)] = weights[i];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    for (unsigned int s = get_local_size(0) / 2; s > 0; s >>= 1) {
        if (get_local_id(0) < s) {
            buffer[get_local_id(0)] += buffer[get_local_id(0) + s];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }
    if (get_local_id(0) == 0) {
        partial_sums[get_group_id(0)] = buffer[0];
    }
    barrier(CLK_GLOBAL_MEM_FENCE);
}

